def shipping_label(weight: int) -> str {
    if weight <= 0 {
        return "invalid";
    }
    if weight <= 2 {
        return "letter";
    }
    if weight <= 10 {
        return "parcel";
    }
    return "freight";
}

with entry {
    print(shipping_label(7));
    print(shipping_label(15));
}

node Counter {
    has value: int = 0;

    def add(step: int) -> int {
        self.value = self.value + step;
        return self.value;
    }
}

with entry {
    c = Counter(value=10);
    print(c.add(5));
    print(c.add(2));
}

def status_text(code: int) -> str {
    if code == 200 {
        return "ok";
    }
    if code == 404 {
        return "not found";
    }
    if code == 500 {
        return "server error";
    }
    return "unknown";
}

with entry {
    print(status_text(200));
    print(status_text(404));
}

