node Endpoint {
    has path: str;
    has method: str;
    has handler: str;
}

def route_name(routes: list[Endpoint], path: str, method: str) -> str {
    for route in routes {
        if route.path == path and route.method == method {
            return route.handler;
        }
    }
    return "not_found";
}

with entry {
    routes = [Endpoint(path="/", method="GET", handler="home"), Endpoint(path="/login", method="POST", handler="login")];
    print(route_name(routes, "/login", "POST"));
}

def clamp_readings(values: list[int], low: int, high: int) -> list[int] {
    result: list[int] = [];
    for value in values {
        if value < low {
            result.append(low);
        } elif value > high {
            result.append(high);
        } else {
            result.append(value);
        }
    }
    return result;
}

with entry {
    print(clamp_readings([3, 10, 25, 7], 5, 20));
}
